@Configuration
@EnableWebSocketMessageBroker
public class WebSocketConfig implements WebSocketMessageBrokerConfigurer {
    @Override
    public void configureMessageBroker(MessageBrokerRegistry registry) {
        registry.enableSimpleBroker("/topic", "/queue");
        registry.setApplicationDestinationPrefixes("/app");
    }

    @Override
    public void registerStompEndpoints(StompEndpointRegistry registry) {
        registry.addEndpoint("/ws").setAllowedOriginPatterns("*").withSockJS();
    }
}

// Cassandra table: messages
// PRIMARY KEY ((conversation_id), message_id)
// WITH CLUSTERING ORDER BY (message_id DESC)

@Query("SELECT * FROM messages WHERE conversation_id = :conversationId "
     + "AND message_id < :beforeId LIMIT :limit")
List<Message> fetchBefore(
    @Param("conversationId") UUID conversationId,
    @Param("beforeId") long beforeId,
    @Param("limit") int limit);

@Service
public class MessageFanout {
    private final RedisTemplate<String, MessageEvent> redis;

    public void publish(UUID conversationId, MessageEvent event) {
        redis.convertAndSend("chat:" + conversationId, event);
    }

    @Bean
    public MessageListenerAdapter listenerAdapter(ChatMessageHandler handler) {
        return new MessageListenerAdapter(handler, "onMessage");
    }
}
